import 'dotenv/config';
import express from 'express';
import userRoutes from './modules/user/user.routes';
import authRoutes from './modules/auth/auth.routes';
import productRoutes from './modules/product/product.routes';

const app = express();

// Middleware setup
app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.use('/api/users', userRoutes);
app.use('/api/auth', authRoutes);
app.use(productRoutes);

// Define routes
app.get('/', (req, res) => {
    res.send('Welcome to the Cheva Telivery API!');
});

// Export the app for use in server.ts
export default app;

import { Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';
import { createProductSchema } from './product.schema';
import path from 'path';
import fs from 'fs';

const prisma = new PrismaClient();

export const createProduct = async (req: Request, res: Response) => {
  try {
    // Pastikan user sudah login dan role penjual
    const user = req.user;
    if (!user || user.role !== 'penjual') {
      return res.status(403).json({ message: 'Unauthorized, hanya penjual yang dapat menambah produk.' });
    }

    // Validasi input
    const { nama, harga, stok, kategori } = createProductSchema.parse(req.body);
    if (!req.file) {
      return res.status(400).json({ message: 'Gambar produk wajib diupload.' });
    }

    // Simpan gambar ke /uploads/produk/ dengan nama unik
    const uploadDir = path.join(__dirname, '../../uploads/produk');
    if (!fs.existsSync(uploadDir)) {
      fs.mkdirSync(uploadDir, { recursive: true });
    }
    const ext = path.extname(req.file.originalname);
    const fileName = `produk-${Date.now()}-${Math.round(Math.random() * 1e9)}${ext}`;
    const filePath = path.join(uploadDir, fileName);
    fs.writeFileSync(filePath, req.file.buffer);
    const pathGambar = `/uploads/produk/${fileName}`;

    // Mapping kategori ke id_kategori
    let id_kategori: number | null = null;
    const kategoriRow = await prisma.kategori.findFirst({ where: { nama_kategori: kategori } });
    if (kategoriRow) id_kategori = kategoriRow.id_kategori;

    // Simpan produk ke database
    const produk = await prisma.produk.create({
      data: {
        nama_produk: nama,
        harga: harga,
        stok_produk: stok,
        id_kategori: id_kategori,
        foto: pathGambar,
        mitra_id: user.mitra_id,
        status_ketersediaan: stok > 0,
      },
    });

    return res.status(201).json({ message: 'Produk berhasil ditambahkan', produk });
  } catch (err: any) {
    return res.status(400).json({ message: err.message });
  }
};

import { Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';
import { createProductSchema } from './product.schema';
import path from 'path';
import fs from 'fs';
import { createProductService } from './product.service';

const prisma = new PrismaClient();

export const createProduct = async (req: Request, res: Response) => {
  try {
    // Pastikan user sudah login dan role penjual
    const user = (req as any).user;
    if (!user || user.role_penjual !== 'penjual') {
      return res.status(403).json({ message: 'Unauthorized, hanya penjual yang dapat menambah produk.' });
    }

    // Validasi input
    const { nama, harga, stok, kategori } = createProductSchema.parse(req.body);
    if (!req.file) {
      return res.status(400).json({ message: 'Gambar produk wajib diupload.' });
    }

    // Simpan gambar ke /uploads/produk/ dengan nama unik
    const uploadDir = path.join(__dirname, '../../uploads/produk');
    if (!fs.existsSync(uploadDir)) {
      fs.mkdirSync(uploadDir, { recursive: true });
    }
    const ext = path.extname(req.file.originalname);
    const fileName = `produk-${Date.now()}-${Math.round(Math.random() * 1e9)}${ext}`;
    const filePath = path.join(uploadDir, fileName);
    fs.writeFileSync(filePath, req.file.buffer);
    const pathGambar = `/uploads/produk/${fileName}`;

    // Proses simpan produk ke database via service
    const produk = await createProductService({
      nama,
      harga,
      stok,
      kategori,
      pathGambar,
      mitra_id: user.mitra_id,
    });

    return res.status(201).json({ message: 'Produk berhasil ditambahkan', produk });
  } catch (err: any) {
    return res.status(400).json({ message: err.message });
  }
};

import { Router } from 'express';
import { createProduct } from './product.controller';
import multer from 'multer';
import { jwtAuth } from '../middlewares/jwt.middleware';

const router = Router();

// Setup multer for memory storage
const storage = multer.memoryStorage();
const upload = multer({ storage });

router.post('/api/seller/product', jwtAuth, upload.single('gambar'), createProduct);

export default router;

import { Router } from 'express';
import { createProduct } from './product.controller';
import multer from 'multer';
import { jwtMiddleware } from '../middlewares/jwt.middleware';

const router = Router();

// Setup multer for memory storage
const storage = multer.memoryStorage();
const upload = multer({ storage });

router.post('/api/seller/product', jwtMiddleware, upload.single('gambar'), createProduct);

export default router;

import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

interface CreateProductInput {
  nama: string;
  harga: number;
  stok: number;
  kategori: string;
  pathGambar: string;
  mitra_id: number;
}

export async function createProductService({ nama, harga, stok, kategori, pathGambar, mitra_id }: CreateProductInput) {
  // Cari id_kategori dari nama_kategori
  const kategoriRow = await prisma.kategori.findFirst({ where: { nama_kategori: kategori } });
  if (!kategoriRow) {
    throw new Error('Kategori tidak ditemukan di database');
  }

  // Simpan produk ke database
  const produk = await prisma.produk.create({
    data: {
      nama_produk: nama,
      harga: harga,
      stok_produk: stok,
      id_kategori: kategoriRow.id_kategori,
      foto: pathGambar,
      mitra_id: mitra_id,
      status_ketersediaan: stok > 0,
    },
  });
  return produk;
}
